#!/bin/sh
dir=$1; [[ "$dir" ]] || dir="/"; selection=$(find "$dir" -maxdepth 7 -mount 2>/dev/null | grep -vEi "^$PWD$/usr/lib32/|/usr/include/|/usr/lib/|/opt/|/var/|/proc/|/dev/|/tmp/|cache|/sys/|.{50,}" | sed "s;^\.;$PWD;g" | sed "s;/home/$USER;~;g" | fzf --ansi --scroll-off=5 --height 100% --preview-window=right --scheme=path --cycle --algo=v2 --preview='~/scripts/fzf-preview.sh {}' | sed "s;^~;/home/$USER;g") && [[ "$selection" ]] || return 0; filetype=$(file $selection | awk '{print $2}'); dirpath=$(<<< $selection | rev | cut -d'/' -f2- | rev); filename=$(basename -- "$selection"); extension="${filename##*.}"; filename="${filename%.*}"; [[ "$filetype" = "directory" ]] && cd $selection && return 0; [[ "$filetype" = "PNG" ]] || [[ "$filetype" = "JPEG" ]] && cd $dirpath && $IMGVIEWER $selection && return 0; [[ "$extension" = "c" ]] || [[ "$extension" = "py" ]] || [[ "$extension" = "lua" ]] || [[ "$extension" = "cpp" ]] || [[ "$extension" = "sh" ]] && cd $dirpath && $EDITOR $selection && return 0; [[ "$extension" = "pdf" ]] && cd $dirpath && $PDFVIEWER $selection && return 0; [[ "$filetype" = "Unicode" ]] || [[ "$filetype" = "Python" ]] || [[ "$filetype" = "ASCII" ]] && cd $dirpath && $EDITOR $selection && return 0; shebang=$(< $selection 2>/dev/null sed 1q | grep ^\#!); [[ "$shebang" ]] && cd $dirpath && $EDITOR $selection && return 0; [[ -x "$selection" ]] && $selection && return 0
